class Solution:
    def maximumGood(self, statements):
        n = len(statements)
        best = 0
        for mask in range(1 << n):
            valid = True
            for i in range(n):
                if not (mask & (1 << i)):
                    continue
                for j in range(n):
                    v = statements[i][j]
                    if v == 2:
                        continue
                    j_is_good = bool(mask & (1 << j))
                    if v == 1 and not j_is_good:
                        valid = False
                        break
                    if v == 0 and j_is_good:
                        valid = False
                        break
                if not valid:
                    break
            if valid:
                count = bin(mask).count('1')
                if count > best:
                    best = count
        return best

