class Solution:
    def maximumGood(self, statements):
        n = len(statements)
        best = 0
        for mask in range((1 << n) - 1, -1, -1):
            count = bin(mask).count('1')
            if count <= best:
                continue
            valid = True
            for i in range(n):
                if not (mask & (1 << i)):
                    continue
                row = statements[i]
                for j in range(n):
                    v = row[j]
                    if v == 2:
                        continue
                    j_is_good = bool(mask & (1 << j))
                    if (v == 1 and not j_is_good) or (v == 0 and j_is_good):
                        valid = False
                        break
                if not valid:
                    break
            if valid:
                best = count
        return best

