var maximumGood = function(statements) {
    const n = statements.length;
    let best = 0;
    for (let mask = (1 << n) - 1; mask >= 0; mask--) {
        let count = 0;
        for (let b = 0; b < n; b++) if (mask & (1 << b)) count++;
        if (count <= best) continue;
        let valid = true;
        for (let i = 0; i < n && valid; i++) {
            if (!(mask & (1 << i))) continue;
            const row = statements[i];
            for (let j = 0; j < n; j++) {
                const v = row[j];
                if (v === 2) continue;
                const jIsGood = (mask & (1 << j)) !== 0;
                if ((v === 1 && !jIsGood) || (v === 0 && jIsGood)) {
                    valid = false;
                    break;
                }
            }
        }
        if (valid) best = count;
    }
    return best;
};
